/// <summary>
/// HospitalCode lookup EventHandler
/// </summary>
/// <param name="sender">FormControl</param>
/// <param name="e">FormControlEventArgs</param>
[FormControlEventHandler(formControlStr(InventJournalMovement, InventJournalTable_KJPSMHospitalCode), FormControlEventType::Lookup)]
public static void InventJournalTable_KJPSMHospitalCode_OnLookup(FormControl sender, FormControlEventArgs e)
{
    FormControlCancelableSuperEventArgs cancelableSuperEvent = e as FormControlCancelableSuperEventArgs;
    // Cancel call Super lookup method
    cancelableSuperEvent.CancelSuperCall();
    KJP_SM_HospitalMasterView::lookupHospitalMaster(sender);
}
